// constants
const leftFeatures = [
  {
    title: "Fast & Easy Work",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    title: "Clean Code",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
];

const rightFeatures = [
  {
    title: "Creative Design",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    title: "Quick Result",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
];

//  ------------------------------ | FEATURE - 10 | ------------------------------  //

export default function Feature10() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header Section */}
        <div className="mx-auto max-w-2xl text-center mb-8 lg:mb-12">
          <h2 className="mb-6">Features</h2>
          <p className="text-lg">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led the way to an adjoining hall.
          </p>
        </div>

        {/* Features Grid */}
        <div className="grid grid-cols-12 gap-6 items-center justify-between">
          {/* Left Column: Right-aligned text */}
          <div className="col-span-12 md:col-span-4 flex flex-col gap-6 text-center md:text-left">
            {leftFeatures.map((item, index) => (
              <div key={index} className="flex flex-col gap-3">
                <h5>{item.title}</h5>
                <p className="text-muted-foreground">{item.description}</p>
              </div>
            ))}
          </div>

          {/* Center Column: Mobile Mockup */}
          <div className="col-span-12 md:col-span-4 flex justify-center">
            <div className="relative w-full max-w-65">
              <img
                src="https://cdn.uiable.com/block/content-29.png"
                alt="Meetings App Interface"
                className="h-auto w-full object-contain"
              />
            </div>
          </div>

          {/* Right Column: Left-aligned text */}
          <div className="col-span-12 md:col-span-4 flex flex-col gap-6 text-center md:text-right">
            {rightFeatures.map((item, index) => (
              <div key={index} className="flex flex-col gap-3">
                <h5>{item.title}</h5>
                <p className="text-muted-foreground">{item.description}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
